// Parse incoming test results
const data = items[0].json;
const failedTests = (data.results || []).filter(r => r.status === 'failed');
const passedTests = (data.results || []).filter(r => r.status === 'passed');

return [{
  json: {
    project: data.project || 'unknown',
    timestamp: data.timestamp,
    total: data.total,
    passed: passedTests.length,
    failed: failedTests.length,
    failedTests: failedTests,
    hasFailed: failedTests.length > 0
  }
}];

// AI Analysis simulation - generate bug report for each failed test
const failed = items[0].json.failedTests;
const bugs = failed.map(t => ({
  project: items[0].json.project,
  title: t.test,
  severity: t.error && t.error.includes('security') ? 'critical' : 'high',
  file: t.file,
  line: t.line,
  error: t.error,
  status: 'open',
  aiAnalysis: `Test '${t.test}' failed. Root cause: Input validation missing for special characters. Recommendation: Add input sanitization before processing.`,
  createdAt: new Date().toISOString()
}));

return bugs.map(b => ({ json: b }));

// Save bug to file (in real scenario, use database node)
const bug = items[0].json;
console.log('Bug saved:', JSON.stringify(bug));
return items;
